={{ (function(raw){
  raw = raw || '';
  // Try JSON.parse on common chat fields
  try {
    const parsed = (typeof raw === 'object') ? raw : JSON.parse(raw);
    if (parsed && parsed.relevance != null) return Number(parsed.relevance);
  } catch(e) {}
  // Try double-parse (escaped JSON inside string)
  try {
    const step = JSON.parse(raw);
    const parsed2 = (typeof step === 'string') ? JSON.parse(step) : step;
    if (parsed2 && parsed2.relevance != null) return Number(parsed2.relevance);
  } catch(e) {}
  // Regex fallback (works on any string)
  const s = raw.toString();
  const m = s.match(/"relevance"\s*:\s*([0-9]{1,3})/i) || s.match(/relevance\s*:\s*([0-9]{1,3})/i);
  return m ? Number(m[1]) : 0;
})(
  $json.output?.[0]?.content?.[0]?.text 
  || ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) 
  || $json.text 
  || ''
) }}

